mapper.select:
		
		select
			recoveryid, phase, old_orderid, new_orderid, keymap_id, basedate, old_jobid, old_version, new_jobid, status, regdate, upddate, reguserid, upduserid
		from (
				select
					 ROWNUM rn, recoveryid, phase, old_orderid, new_orderid, keymap_id, basedate, old_jobid, old_version, new_jobid, status, regdate, upddate, reguserid, upduserid
				from (
						select recoveryid, phase, old_orderid, new_orderid, keymap_id, to_char(basedate,'yyyy/mm/dd') as basedate, old_jobid, old_version, new_jobid, status, to_char(regdate,'yyyy/mm/dd hh24:mi:ss') as regdate, to_char(upddate,'yyyy/mm/dd') as upddate, reguserid, upduserid
						  from cotdl.tbl_piirecovery order by recoveryid desc
					 ) a
				where 1=1
		

		

	    
				  and  ROWNUM <= #{pagenum} * #{amount}
				order by recoveryid
			  ) k
		where rn > (#{pagenum} -1) * #{amount}
		order by recoveryid desc
